79	    pub(crate) async fn add_peer_connector(&self) -> usize {
80	        let mut peer_connectors = self.peer_connectors.lock().await;
81	        peer_connectors.push(PeerConnector::default());
82	        peer_connectors.len() - 1
83	    }
