85	    pub(crate) async fn add_peer_connector_zid(&self, zid: ZenohIdProto) {
86	        let mut peer_connectors = self.peer_connectors.lock().await;
87	        if !peer_connectors.iter().any(|pc| pc.zid == Some(zid)) {
88	            peer_connectors.push(PeerConnector {
89	                zid: Some(zid),
90	                terminated: false,
91	            })
92	        }
93	    }
