95	    pub(crate) async fn set_peer_connector_zid(&self, idx: usize, zid: ZenohIdProto) {
96	        let mut peer_connectors = self.peer_connectors.lock().await;
97	        if let Some(peer_connector) = peer_connectors.get_mut(idx) {
98	            peer_connector.zid = Some(zid);
99	        }
100	    }
101	
102	    pub(crate) async fn terminate_peer_connector(&self, idx: usize) {
103	        let mut peer_connectors = self.peer_connectors.lock().await;
104	        if let Some(peer_connector) = peer_connectors.get_mut(idx) {
105	            peer_connector.terminated = true;
106	        }
107	        if peer_connectors.iter().all(|pc| pc.terminated) {
108	            self.notify.notify_one()
109	        }
110	    }
111	
112	    pub(crate) async fn terminate_peer_connector_zid(&self, zid: ZenohIdProto) {
113	        let mut peer_connectors = self.peer_connectors.lock().await;
114	        if let Some(peer_connector) = peer_connectors.iter_mut().find(|pc| pc.zid == Some(zid)) {
115	            peer_connector.terminated = true;
116	        } else {
117	            peer_connectors.push(PeerConnector {
118	                zid: Some(zid),
119	                terminated: true,
120	            })
121	        }
122	        if peer_connectors.iter().all(|pc| pc.terminated) {
123	            self.notify.notify_one()
124	        }
125	    }
126	}
