140	    pub async fn start(&mut self) -> ZResult<()> {
141	        match self.whatami() {
142	            WhatAmI::Client => self.start_client().await,
143	            WhatAmI::Peer => self.start_peer().await,
144	            WhatAmI::Router => self.start_router().await,
145	        }
