148	    async fn start_client(&self) -> ZResult<()> {
149	        let (listeners, peers, scouting, listen, autoconnect, addr, ifaces, timeout, multicast_ttl) = {
150	            let guard = &self.state.config.lock();
151	            (
152	                guard
153	                    .listen()
154	                    .endpoints()
155	                    .client()
156	                    .unwrap_or(&vec![])
157	                    .clone(),
158	                guard
159	                    .connect()
160	                    .endpoints()
161	                    .client()
162	                    .unwrap_or(&vec![])
163	                    .clone(),
164	                unwrap_or_default!(guard.scouting().multicast().enabled()),
165	                *unwrap_or_default!(guard.scouting().multicast().listen().client()),
166	                *unwrap_or_default!(guard.scouting().multicast().autoconnect().client()),
167	                unwrap_or_default!(guard.scouting().multicast().address()),
168	                unwrap_or_default!(guard.scouting().multicast().interface()),
169	                std::time::Duration::from_millis(unwrap_or_default!(guard.scouting().timeout())),
170	                unwrap_or_default!(guard.scouting().multicast().ttl()),
171	            )
172	        };
173	
174	        self.bind_listeners(&listeners).await?;
175	
176	        if scouting {
177	            if listen || peers.is_empty() {
178	                let ifaces = Runtime::get_interfaces(&ifaces);
179	                let mcast_socket = if listen {
180	                    Some(Runtime::bind_mcast_port(&addr, &ifaces, multicast_ttl).await?)
181	                } else {
182	                    None
183	                };
184	                if ifaces.is_empty() {
185	                    bail!("Unable to find multicast interface!")
186	                } else {
187	                    let sockets: Vec<UdpSocket> = ifaces
188	                        .into_iter()
189	                        .filter_map(|iface| Runtime::bind_ucast_port(iface, multicast_ttl).ok())
190	                        .collect();
191	                    if sockets.is_empty() {
192	                        bail!("Unable to bind UDP port to any multicast interface!")
193	                    } else {
194	                        if peers.is_empty() {
195	                            self.connect_first(&sockets, autoconnect, &addr, timeout)
196	                                .await?
197	                        }
198	                        if let Some(mcast_socket) = mcast_socket {
199	                            let this = self.clone();
200	                            self.spawn_abortable(async move {
201	                                this.responder(&mcast_socket, &sockets).await;
202	                            });
203	                        }
204	                    }
205	                }
206	            }
207	            if !peers.is_empty() {
208	                self.connect_peers(&peers, true).await
209	            } else {
210	                Ok(())
211	            }
212	        } else if peers.is_empty() {
213	            bail!("No peer specified and multicast scouting deactivated!")
214	        } else {
215	            self.connect_peers(&peers, true).await
216	        }
217	    }
