297	    async fn start_scout(
298	        &self,
299	        listen: bool,
300	        autoconnect: AutoConnect,
301	        addr: SocketAddr,
302	        ifaces: String,
303	    ) -> ZResult<()> {
304	        let multicast_ttl = {
305	            let config_guard = self.config().lock();
306	            let config = &config_guard;
307	            unwrap_or_default!(config.scouting().multicast().ttl())
308	        };
309	        let ifaces = Runtime::get_interfaces(&ifaces);
310	        let mcast_socket = Runtime::bind_mcast_port(&addr, &ifaces, multicast_ttl).await?;
311	        if !ifaces.is_empty() {
312	            let sockets: Vec<UdpSocket> = ifaces
313	                .into_iter()
314	                .filter_map(|iface| Runtime::bind_ucast_port(iface, multicast_ttl).ok())
315	                .collect();
316	            if !sockets.is_empty() {
317	                let this = self.clone();
318	                match (listen, autoconnect.is_enabled()) {
319	                    (true, true) => {
320	                        self.spawn_abortable(async move {
321	                            tokio::select! {
322	                                _ = this.responder(&mcast_socket, &sockets) => {},
323	                                _ = this.autoconnect_all(
324	                                    &sockets,
325	                                    autoconnect,
326	                                    &addr
327	                                ) => {},
328	                            }
329	                        });
330	                    }
331	                    (true, false) => {
332	                        self.spawn_abortable(async move {
333	                            this.responder(&mcast_socket, &sockets).await;
334	                        });
335	                    }
336	                    (false, true) => {
337	                        self.spawn_abortable(async move {
338	                            this.autoconnect_all(&sockets, autoconnect, &addr).await
339	                        });
340	                    }
341	                    _ => {}
342	                }
343	            }
344	        }
345	        Ok(())
346	    }
