368	    async fn connect_peers_impl(&self, peers: &[EndPoints], single_link: bool) -> ZResult<()> {
369	        if single_link {
370	            self.connect_peers_single_link(peers).await
371	        } else {
372	            self.connect_peers_multiply_links(peers).await
373	        }
374	    }
