376	    async fn connect_peers_single_link(&self, peers: &[EndPoints]) -> ZResult<()> {
377	        let mut success_flag = false;
378	        for peer_group in peers {
379	            Self::warn_if_oneof(peer_group);
380	            // try to connect to each peer in the group
381	            let mut peers_to_retry = Vec::new();
382	            for peer in peer_group.as_vec() {
383	                let endpoint = peer.clone();
384	                let retry_config = self.get_connect_retry_config(&endpoint);
385	                if retry_config.timeout().is_zero() || self.get_global_connect_timeout().is_zero() {
386	                    tracing::debug!(
387	                        "Try to connect: {:?}: global timeout: {:?}, retry: {:?}",
388	                        endpoint,
389	                        self.get_global_connect_timeout(),
390	                        retry_config
391	                    );
392	                    // try to connect directly when there is no timeout configuration
393	                    if self.peer_connector(endpoint).await.is_ok() {
394	                        success_flag = true;
395	                    }
396	                } else {
397	                    peers_to_retry.push(endpoint);
398	                }
399	            }
400	            // sequentially try to connect to one of the remaining peers
401	            // respecting connection retry delays
402	            if self
403	                .peers_connector_retry(peers_to_retry, false)
404	                .await
405	                .is_ok()
406	            {
407	                success_flag = true;
408	            }
409	            // any endpoint in the group is available, it's marked as success and break
410	            if success_flag {
411	                break;
412	            }
413	        }
414	
415	        // return error if none of them succeeded
416	        if success_flag {
417	            Ok(())
418	        } else {
419	            let e = zerror!("Unable to connect to any of {:?}! ", peers);
420	            tracing::warn!("{}", &e);
421	            Err(e.into())
422	        }
423	    }
