425	    async fn connect_peers_multiply_links(&self, peers: &[EndPoints]) -> ZResult<()> {
426	        for peer_group in peers {
427	            Self::warn_if_oneof(peer_group);
428	            for peer in peer_group.as_vec() {
429	                let endpoint = peer.clone();
430	                let retry_config = self.get_connect_retry_config(&endpoint);
431	                tracing::debug!(
432	                    "Try to connect: {:?}: global timeout: {:?}, retry: {:?}",
433	                    endpoint,
434	                    self.get_global_connect_timeout(),
435	                    retry_config
436	                );
437	                if retry_config.timeout().is_zero() || self.get_global_connect_timeout().is_zero() {
438	                    // try to connect and exit immediately without retry
439	                    if let Err(e) = self.peer_connector(endpoint).await {
440	                        if retry_config.exit_on_failure {
441	                            return Err(e);
442	                        }
443	                    }
444	                } else if retry_config.exit_on_failure {
445	                    // try to connect with retry waiting
446	                    let _ = self.peer_connector_retry(endpoint).await;
447	                } else {
448	                    // try to connect in background
449	                    if let Err(e) = self.spawn_peer_connector(endpoint.clone()).await {
450	                        tracing::warn!("Error connecting to {}: {}", endpoint, e);
451	                        return Err(e);
452	                    }
453	                }
454	            }
455	        }
456	        Ok(())
457	    }
