549	    async fn spawn_add_listener(
550	        &self,
551	        listener: EndPoint,
552	        retry_config: zenoh_config::ConnectionRetryConf,
553	    ) {
554	        let this = self.clone();
555	        self.spawn(async move {
556	            this.add_listener_retry(listener, retry_config).await;
557	            this.print_locators();
558	        });
559	    }
