561	    async fn add_listener_retry(
562	        &self,
563	        listener: EndPoint,
564	        retry_config: zenoh_config::ConnectionRetryConf,
565	    ) {
566	        let mut period = retry_config.period();
567	        loop {
568	            if self.add_listener(listener.clone()).await.is_ok() {
569	                break;
570	            }
571	            tokio::time::sleep(period.next_duration()).await;
572	        }
573	    }
