575	    async fn add_listener(&self, listener: EndPoint) -> ZResult<()> {
576	        let endpoint = listener.clone();
577	        match self.manager().add_listener(endpoint).await {
578	            Ok(listener) => tracing::debug!("Listener added: {}", listener),
579	            Err(err) => {
580	                tracing::warn!("Unable to open listener {}: {}", listener, err);
581	                return Err(err);
582	            }
583	        }
584	        Ok(())
585	    }
