595	    pub fn get_interfaces(names: &str) -> Vec<IpAddr> {
596	        if names == "auto" {
597	            let ifaces = zenoh_util::net::get_multicast_interfaces();
598	            if ifaces.is_empty() {
599	                tracing::warn!(
600	                    "Unable to find active, non-loopback multicast interface. Will use [::]."
601	                );
602	                vec![Ipv6Addr::UNSPECIFIED.into()]
603	            } else {
604	                ifaces
605	            }
606	        } else {
607	            names
608	                .split(',')
609	                .filter_map(|name| match name.trim().parse::<IpAddr>() {
610	                    Ok(addr) => Some(addr),
611	                    Err(_) => match zenoh_util::net::get_interface(name.trim()) {
612	                        Ok(opt_addr) => match opt_addr {
613	                            Some(addr) => Some(addr),
614	                            None => {
