791	    async fn peers_connector_retry(
792	        &self,
793	        peers: Vec<EndPoint>,
794	        stop_after_first_connection: bool,
795	    ) -> ZResult<Vec<ZenohIdProto>> {
796	        async fn wait_next_peer_retry(
797	            peer: EndPoint,
798	            period: ConnectionRetryPeriod,
799	            wait_time: Duration,
800	            cancellation_token: CancellationToken,
801	        ) -> Option<(EndPoint, ConnectionRetryPeriod)> {
802	            tokio::select! {
803	                _ = tokio::time::sleep(wait_time) => {
804	                    Some((peer, period))
805	                }
806	                _ = cancellation_token.cancelled() => {
807	                    None
808	                }
809	            }
810	        }
811	
812	        let mut connected_peers = Vec::new();
813	
814	        let mut tasks = FuturesUnordered::new();
815	        let cancellation_token = self.get_cancellation_token();
816	
817	        for peer in peers {
818	            let retry_config = self.get_connect_retry_config(&peer);
819	            let period = retry_config.period();
820	            tasks.push(wait_next_peer_retry(
821	                peer,
822	                period,
823	                Duration::ZERO,
824	                cancellation_token.clone(),
825	            ));
826	        }
827	
828	        while let Some(task) = tasks.next().await {
829	            if let Some((peer, mut period)) = task {
830	                tracing::debug!(
831	                    "Try to connect: {:?}: global timeout: {:?}, retry: {:?}",
832	                    peer,
833	                    self.get_global_connect_timeout(),
834	                    self.get_connect_retry_config(&peer)
835	                );
836	                let result = self
837	                    .manager()
838	                    .open_transport_unicast(peer.clone())
839	                    .await
840	                    .and_then(|transport| -> ZResult<_> {
841	                        let zid = transport.get_zid()?;
842	                        let cb = transport
843	                            .get_callback()?
844	                            .ok_or_else(|| zerror!("Transport closed immediately"))?;
845	                        let session = cb
846	                            .as_any()
847	                            .downcast_ref::<super::RuntimeSession>()
848	                            .ok_or_else(|| zerror!("Unexpected callback type"))?;
849	                        zwrite!(session.endpoints).insert(peer.clone());
850	                        Ok(zid)
851	                    });
852	
853	                match result {
854	                    Ok(zid) => {
855	                        tracing::debug!("Successfully connected to configured peer {}", peer);
856	                        connected_peers.push(zid);
857	                        if stop_after_first_connection {
858	                            break;
859	                        }
860	                    }
861	                    Err(e) => {
862	                        tracing::debug!(
863	                            "Unable to connect to configured peer {}! {}. Retry in {:?}.",
864	                            peer,
865	                            e,
866	                            period.duration()
867	                        );
868	                        let wait_time = period.next_duration();
869	                        tasks.push(wait_next_peer_retry(
870	                            peer,
871	                            period,
872	                            wait_time,
873	                            cancellation_token.clone(),
874	                        ));
875	                    }
876	                }
877	            }
878	        }
879	        if connected_peers.is_empty() {
880	            bail!("Peer connector terminated without connecting to any endpoint")
881	        } else {
882	            Ok(connected_peers)
883	        }
884	    }
