892	    pub async fn scout<Fut, F>(
893	        sockets: &[UdpSocket],
894	        matcher: WhatAmIMatcher,
895	        mcast_addr: &SocketAddr,
896	        f: F,
897	    ) where
898	        F: Fn(HelloProto) -> Fut + std::marker::Send + std::marker::Sync + Clone,
899	        Fut: Future<Output = Loop> + std::marker::Send,
900	        Self: Sized,
901	    {
902	        let send = async {
903	            let mut delay = SCOUT_INITIAL_PERIOD;
904	
905	            let scout: ScoutingMessage = Scout {
906	                version: zenoh_protocol::VERSION,
907	                what: matcher,
908	                zid: None,
909	            }
910	            .into();
911	            let mut wbuf = vec![];
912	            let mut writer = wbuf.writer();
913	            let codec = Zenoh080::new();
914	            codec.write(&mut writer, &scout).unwrap();
915	
916	            loop {
917	                for socket in sockets {
918	                    tracing::trace!(
919	                        "Send {:?} to {} on interface {}",
920	                        scout.body,
921	                        mcast_addr,
922	                        socket
923	                            .local_addr()
924	                            .map_or("unknown".to_string(), |addr| addr.ip().to_string())
925	                    );
926	                    if let Err(err) = socket
927	                        .send_to(wbuf.as_slice(), mcast_addr.to_string())
928	                        .await
929	                    {
930	                        tracing::debug!(
931	                            "Unable to send {:?} to {} on interface {}: {}",
932	                            scout.body,
933	                            mcast_addr,
934	                            socket
935	                                .local_addr()
936	                                .map_or("unknown".to_string(), |addr| addr.ip().to_string()),
937	                            err
938	                        );
939	                    }
940	                }
941	                tokio::time::sleep(delay).await;
942	                if delay * SCOUT_PERIOD_INCREASE_FACTOR <= SCOUT_MAX_PERIOD {
943	                    delay *= SCOUT_PERIOD_INCREASE_FACTOR;
944	                }
945	            }
946	        };
947	        let recvs = futures::future::select_all(sockets.iter().map(move |socket| {
948	            let f = f.clone();
949	            async move {
950	                let mut buf = vec![0; RCV_BUF_SIZE];
951	                loop {
952	                    match socket.recv_from(&mut buf).await {
953	                        Ok((n, peer)) => {
954	                            let mut reader = buf.as_slice()[..n].reader();
955	                            let codec = Zenoh080::new();
956	                            let res: Result<ScoutingMessage, DidntRead> = codec.read(&mut reader);
957	                            if let Ok(msg) = res {
958	                                tracing::trace!("Received {:?} from {}", msg.body, peer);
959	                                if let ScoutingBody::Hello(hello) = &msg.body {
960	                                    if matcher.matches(hello.whatami) {
961	                                        if let Loop::Break = f(hello.clone()).await {
962	                                            break;
963	                                        }
964	                                    } else {
965	                                        tracing::warn!("Received unexpected Hello: {:?}", msg.body);
966	                                    }
967	                                }
968	                            } else {
969	                                tracing::trace!(
970	                                    "Received unexpected UDP datagram from {}: {:?}",
971	                                    peer,
972	                                    &buf.as_slice()[..n]
973	                                );
974	                            }
975	                        }
976	                        Err(e) => tracing::debug!("Error receiving UDP datagram: {}", e),
977	                    }
978	                }
979	            }
980	            .boxed()
981	        }));
982	        tokio::select! {
983	            _ = send => {},
984	            _ = recvs => {},
985	        }
986	    }
