988	    /// Returns `true` if a new Transport instance is established with `zid` or had already been established.
989	    #[must_use]
990	    async fn connect(&self, zid: &ZenohIdProto, scouted_locators: &[Locator]) -> bool {
991	        if !self.insert_pending_connection(*zid).await {
992	            tracing::debug!("Already connecting to {}. Ignore.", zid);
993	            return false;
994	        }
995	
996	        const ERR: &str = "Unable to connect to newly scouted peer";
997	
998	        let configured_locators = self
999	            .state
1000	            .config
1001	            .lock()
1002	            .connect()
1003	            .endpoints()
1004	            .get(self.whatami())
1005	            .unwrap_or(&vec![])
1006	            .iter()
1007	            .flat_map(|e| e.as_vec())
1008	            .map(|e| e.to_locator())
1009	            .collect::<HashSet<_>>();
1010	
1011	        let locators = scouted_locators
1012	            .iter()
1013	            .filter(|l| !configured_locators.contains(l))
1014	            .collect::<Vec<&Locator>>();
1015	
1016	        if locators.is_empty() {
1017	            tracing::debug!(
1018	                "Already connecting to locators of {} (connect configuration). Ignore.",
1019	                zid
1020	            );
1021	            return false;
1022	        }
1023	
1024	        let manager = self.manager();
1025	
1026	        let inspector = LocatorInspector::default();
1027	        for locator in locators {
1028	            let is_multicast = match inspector.is_multicast(locator).await {
1029	                Ok(im) => im,
1030	                Err(e) => {
1031	                    tracing::trace!("{} {} on {}: {}", ERR, zid, locator, e);
1032	                    continue;
1033	                }
1034	            };
1035	
1036	            let endpoint = locator.to_owned().into();
1037	            let priorities = locator
1038	                .metadata()
1039	                .get(Metadata::PRIORITIES)
1040	                .and_then(|p| PriorityRange::from_str(p).ok());
1041	            let reliability = inspector.is_reliable(locator).ok();
1042	            if !manager
1043	                .get_transport_unicast(zid)
1044	                .await
1045	                .as_ref()
1046	                .is_some_and(|t| {
1047	                    t.get_links().is_ok_and(|ls| {
1048	                        ls.iter().any(|l| {
1049	                            l.priorities == priorities
1050	                                && inspector.is_reliable(&l.dst).ok() == reliability
1051	                        })
1052	                    })
1053	                })
1054	            {
1055	                if is_multicast {
1056	                    match manager.open_transport_multicast(endpoint).await {
1057	                        Ok(transport) => {
1058	                            tracing::debug!(
1059	                                "Successfully connected to newly scouted peer: {:?}",
1060	                                transport
1061	                            );
1062	                        }
1063	                        Err(e) => tracing::trace!("{} {} on {}: {}", ERR, zid, locator, e),
1064	                    }
1065	                } else {
1066	                    match manager.open_transport_unicast_with_zid(endpoint, zid).await {
1067	                        Ok(transport) => {
1068	                            tracing::debug!(
1069	                                "Successfully connected to newly scouted peer: {:?}",
1070	                                transport
1071	                            );
1072	                        }
1073	                        Err(e) => tracing::trace!("{} {} on {}: {}", ERR, zid, locator, e),
1074	                    }
1075	                }
1076	            } else {
1077	                tracing::trace!(
1078	                    "Will not attempt to connect to {} via {}: already connected to this peer for this PriorityRange-Reliability pair",
1079	                    zid, locator
1080	                );
1081	            }
1082	        }
1083	
1084	        self.remove_pending_connection(zid).await;
1085	
1086	        if self.manager().get_transport_unicast(zid).await.is_none() {
1087	            tracing::warn!(
1088	                "Unable to connect to any locator of scouted peer {}: {:?}",
1089	                zid,
1090	                scouted_locators
1091	            );
1092	            false
1093	        } else {
1094	            true
1095	        }
1096	    }
