539	        &self,
540	        zid: &ZenohId,
541	    ) -> Box<dyn Iterator<Item = Link> + Send + Sync> {
542	        let links = self
543	            .get_transports_unicast_peers()
544	            .into_iter()
545	            .find(|peer| &ZenohId::from(peer.zid) == zid)
546	            .map(|peer| {
547	                let zid: ZenohId = peer.zid.into();
548	                let is_qos = peer.is_qos;
549	                peer.links
550	                    .into_iter()
551	                    .map(move |ref link| Link::new(zid, link, is_qos))
552	                    .collect::<Vec<_>>()
553	            })
554	            .unwrap_or_default();
555	
556	        Box::new(links.into_iter())
557	    }
